def _extract_emission_value(values_dict, df, primary_key, fallback_keys=()):
    if isinstance(values_dict, dict):
        for k in (primary_key, *fallback_keys):
            if k in values_dict:
                return float(values_dict[k])
    if df is not None and len(df) > 0:
        for k in (primary_key, *fallback_keys):
            if k in df.columns:
                return float(df.iloc[0][k])
